import React, { useState, useEffect, useCallback } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

const GroupDetail = () => {
  const { id } = useParams();
  const [group, setGroup] = useState(null);
  const [isMember, setIsMember] = useState(false);
  const [loading, setLoading] = useState(true);
  const user = JSON.parse(localStorage.getItem('user') || '{}');
  const token = localStorage.getItem('token');

  const fetchGroup = useCallback(async () => {
    try {
      const res = await axios.get(`http://localhost:5000/api/groups/${id}`);
      setGroup(res.data.group);
      const members = res.data.group.Users || [];
      setIsMember(members.some(m => m.id === user.id));
    } catch (err) {
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  }, [id, user.id]);

  useEffect(() => {
    fetchGroup();
  }, [fetchGroup]);

 const handleJoin = async () => {
  try {
    console.log('Joining group:', id); // Debug log
    const response = await axios.post(
      `http://localhost:5000/api/memberships/join/${id}`,
      {},
      { headers: { Authorization: `Bearer ${token}` } }
    );
    console.log('Join response:', response.data); // Debug log
    fetchGroup();
    alert('Successfully joined the group!');
  } catch (err) {
    console.error('Join error:', err.response); // Debug log
    alert(err.response?.data?.message || 'Failed to join group');
  }
};

  if (loading) return <div className="dashboard"><p style={{color: 'white'}}>Loading...</p></div>;
  if (!group) return <div className="dashboard"><p style={{color: 'white'}}>Group not found</p></div>;

  return (
    <div className="dashboard">
      {/* Navigation Buttons */}
      <div style={{display: 'flex', gap: '15px', marginBottom: '30px'}}>
        <a href="/dashboard" style={{
          padding: '12px 24px',
          background: '#1a1a1a',
          color: 'white',
          borderRadius: '8px',
          textDecoration: 'none',
          fontWeight: 'bold'
        }}>đź“Š Dashboard</a>
        
        <a href="/browse" style={{
          padding: '12px 24px',
          background: '#1a1a1a',
          color: 'white',
          borderRadius: '8px',
          textDecoration: 'none',
          fontWeight: 'bold'
        }}>đź”Ť Browse Groups</a>
        
        <a href="/groups/create" style={{
          padding: '12px 24px',
          background: '#1a1a1a',
          color: 'white',
          borderRadius: '8px',
          textDecoration: 'none',
          fontWeight: 'bold'
        }}>âž• Create Group</a>
      </div>

      <div className="card" style={{marginBottom: '30px'}}>
        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px'}}>
          <div>
            <h1 style={{fontSize: '28px', marginBottom: '10px'}}>{group.name}</h1>
            <p className="group-course" style={{fontSize: '16px'}}>{group.course}</p>
          </div>
          {!isMember && (
            <button onClick={handleJoin} style={{
              padding: '12px 24px',
              background: '#8b0000',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              cursor: 'pointer',
              fontWeight: 'bold'
            }}>
              Join Group
            </button>
          )}
        </div>
        <p style={{color: '#666', marginBottom: '20px'}}>{group.description || 'No description'}</p>
        <div className="group-meta" style={{fontSize: '14px'}}>
          <span>đź“Ť {group.location || 'Online'}</span>
          <span>đź‘Ą {group.Users?.length || 0} members</span>
          <span>đź‘¤ Led by: {group.leader?.name}</span>
        </div>
      </div>

      <div className="card">
        <h3 className="card-title">Members</h3>
        {group.Users?.map(member => (
          <div key={member.id} style={{padding: '12px 0', borderBottom: '1px solid #f0f0f0'}}>
            <span style={{fontWeight: '500'}}>{member.name}</span>
            <span style={{color: '#888', marginLeft: '10px', fontSize: '14px'}}>{member.program}</span>
            {member.Membership?.role === 'leader' && (
              <span style={{background: '#fefcbf', color: '#975a16', padding: '2px 8px', borderRadius: '4px', fontSize: '12px', marginLeft: '10px'}}>
                Leader
              </span>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default GroupDetail;
